#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>

typedef uint32_t u32;

typedef struct {
    u32 gl_a, gl_b;
    u32 R3_a, R3_b;
    u32 T;
} PairData;

u32 g_function(u32 a, u32 b, u32 x) {
    u32 temp = (a + b + x) & 0xFF;
    return ((temp << 2) | (temp >> 6)) & 0xFF;
}

u32 f_function(u32 input_val) {
    u32 x[4], y[4];
    for (int i = 0; i < 4; i++) {
        x[i] = input_val & 0xFF;
        input_val >>= 8;
    }
    y[2] = g_function(x[3] ^ x[2], x[1] ^ x[0], 1);
    y[3] = g_function(x[3], y[2], 0);
    y[1] = g_function(x[1] ^ x[0], y[2], 0);
    y[0] = g_function(x[0], y[1], 1);
    u32 output = 0;
    for (int i = 0; i < 4; i++) {
        output |= y[i] << (8 * i);
    }
    return output & 0xFFFFFFFF;
}

u32 ALL_KEYS[65536];

void init_keys() {
    for (int s = 0; s < 65536; s++) {
        ALL_KEYS[s] = ((u32)s * 1234567) & 0xFFFFFFFF;
    }
}

int main(int argc, char **argv) {
    if (argc != 19) {
        fprintf(stderr, "Usage: %s gl0a gl0b R30a R30b T0 gl1a gl1b R31a R31b T1 gl2a gl2b R32a R32b T2 delta0 delta1 delta2\n", argv[0]);
        fprintf(stderr, "Got %d arguments\n", argc);
        return 1;
    }

    init_keys();

    printf("Arguments: ");
    for (int i = 0; i < argc; i++) {
        printf("%s ", argv[i]);
    }
    printf("\n");

    PairData pairs[3];

    for (int i = 0; i < 3; i++) {
        int off = i * 5;
        pairs[i].gl_a = strtoul(argv[off + 1], NULL, 16);
        pairs[i].gl_b = strtoul(argv[off + 2], NULL, 16);
        pairs[i].R3_a = strtoul(argv[off + 3], NULL, 16);
        pairs[i].R3_b = strtoul(argv[off + 4], NULL, 16);
        pairs[i].T = strtoul(argv[off + 5], NULL, 16);
        printf("Pair %d: gl_a=0x%08x gl_b=0x%08x R3_a=0x%08x R3_b=0x%08x T=0x%08x\n",
               i, pairs[i].gl_a, pairs[i].gl_b, pairs[i].R3_a, pairs[i].R3_b, pairs[i].T);
    }

    // Known correct seeds from Python test
    int correct_seeds[5][2] = {{18289, 29256}};  // k5 seed=18289, k4 seed=29256

    for (int si = 0; si < 1; si++) {
        int seed5 = correct_seeds[si][0];
        int seed4 = correct_seeds[si][1];
        u32 k5 = ALL_KEYS[seed5];
        u32 k4 = ALL_KEYS[seed4];

        printf("\nChecking correct seeds: seed5=%d (k5=0x%08x), seed4=%d (k4=0x%08x)\n", seed5, k5, seed4, k4);

        for (int i = 0; i < 3; i++) {
            u32 L3_a = pairs[i].gl_a ^ f_function(pairs[i].R3_a ^ k5);
            u32 L3_b = pairs[i].gl_b ^ f_function(pairs[i].R3_b ^ k5);
            u32 lhs = f_function(L3_a ^ k4) ^ f_function(L3_b ^ k4);
            printf("  Pair %d: L3_a=0x%08x L3_b=0x%08x lhs=0x%08x T=0x%08x match=%s\n",
                   i, L3_a, L3_b, lhs, pairs[i].T, lhs == pairs[i].T ? "true" : "false");
        }
    }

    // Also check: what if we pass the correct k5 but WITHOUT the correct k4?
    // Are there ANY k4 values that satisfy pair 0?
    printf("\nSearching for ANY k4 that works with k5=0x%08x for pair 0...\n", ALL_KEYS[18289]);
    u32 k5_test = ALL_KEYS[18289];
    int found_any = 0;
    for (int s4 = 0; s4 < 65536; s4++) {
        u32 k4_test = ALL_KEYS[s4];
        u32 L3_a = pairs[0].gl_a ^ f_function(pairs[0].R3_a ^ k5_test);
        u32 L3_b = pairs[0].gl_b ^ f_function(pairs[0].R3_b ^ k5_test);
        u32 lhs = f_function(L3_a ^ k4_test) ^ f_function(L3_b ^ k4_test);
        if (lhs == pairs[0].T) {
            printf("  Found! seed4=%d (k4=0x%08x)\n", s4, k4_test);
            found_any++;
            if (found_any >= 5) break;
        }
    }
    if (found_any == 0) {
        printf("  No k4 found!\n");
        // Print the computed values
        u32 L3_a = pairs[0].gl_a ^ f_function(pairs[0].R3_a ^ k5_test);
        u32 L3_b = pairs[0].gl_b ^ f_function(pairs[0].R3_b ^ k5_test);
        printf("  L3_a=0x%08x L3_b=0x%08x T=0x%08x\n", L3_a, L3_b, pairs[0].T);
        // Try k4 = 0x68d473f8
        u32 lhs = f_function(L3_a ^ 0x68d473f8) ^ f_function(L3_b ^ 0x68d473f8);
        printf("  With k4=0x68d473f8: lhs=0x%08x\n", lhs);
    }

    return 0;
}
